import React, { useEffect, useState, useRef } from 'react';
import { db } from '../firebase';
import { doc, updateDoc, increment, collection, query, where, getDocs, deleteDoc, arrayUnion, arrayRemove } from 'firebase/firestore';
import { ArrowLeft, ExternalLink, Calendar, User, LayoutGrid, Image as ImageIcon, Trash2, ImagePlus, Loader2, Heart, Share2, MessageCircle, Send } from 'lucide-react';

function ProjectDetails({ project, onBack }) {
  const [liveAuthorName, setLiveAuthorName] = useState("");
  const [currentImage, setCurrentImage] = useState(project?.imageUrl);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isAppRunning, setIsAppRunning] = useState(false);
  
  const [likes, setLikes] = useState([]);
  const [comments, setComments] = useState([]);
  const [newComment, setNewComment] = useState("");
  const [isLiking, setIsLiking] = useState(false);

  const currentUser = JSON.parse(localStorage.getItem('user_info'));
  const userId = currentUser?.uid || currentUser?.username || currentUser?.id;

  useEffect(() => {
    if (project) {
      setLikes(project.likes || []);
      setComments(project.comments || []);
      setCurrentImage(project.imageUrl);
    }
  }, [project]);

  useEffect(() => {
    if (project?.id) {
      const incrementView = async () => {
        try {
          await updateDoc(doc(db, 'projects', project.id), { views: increment(1) });
        } catch (err) { console.error(err); }
      };
      incrementView();

      const fetchLiveAuthor = async () => {
        let searchUsername = project.authorUsername;
        if (!searchUsername || searchUsername === 'unknown') {
          const match = project.author?.match(/\(([^)]+)\)/);
          if (match) searchUsername = match[1].trim();
        }
        try {
          if (searchUsername && searchUsername !== 'unknown') {
            const q = query(collection(db, "users"), where("username", "==", searchUsername));
            const snapshot = await getDocs(q);
            if (!snapshot.empty) setLiveAuthorName(snapshot.docs[0].data().name);
          }
        } catch (error) { console.error(error); }
      };
      fetchLiveAuthor();
    }
  }, [project]);

  const isOwner = currentUser && (
    currentUser.username === project?.authorUsername || 
    currentUser.name === project?.authorName ||
    project?.author?.includes(currentUser.username)
  );

  const fileInputRef = useRef(null);

  const handleLike = async () => {
    if (!userId) return alert("Please login to like!");
    if (isLiking) return;
    setIsLiking(true);
    const projectRef = doc(db, "projects", project.id);
    const hasLiked = likes.includes(userId);
    try {
      if (hasLiked) {
        await updateDoc(projectRef, { likes: arrayRemove(userId) });
        setLikes(prev => prev.filter(id => id !== userId));
      } else {
        await updateDoc(projectRef, { likes: arrayUnion(userId) });
        setLikes(prev => [...prev, userId]);
      }
    } catch (err) { console.error(err); }
    finally { setIsLiking(false); }
  };

  const handleAddComment = async () => {
    if (!userId) return alert("Please login to comment!");
    if (!newComment.trim()) return;
    const commentData = {
      text: newComment,
      userName: currentUser.name || currentUser.displayName || "User",
      timestamp: new Date().toISOString()
    };
    try {
      await updateDoc(doc(db, "projects", project.id), { comments: arrayUnion(commentData) });
      setComments(prev => [...prev, commentData]);
      setNewComment("");
    } catch (err) { console.error(err); }
  };

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href);
    alert("Project link copied to clipboard!");
  };

  if (!project) return null;
  const isLikedByMe = userId && likes.includes(userId);

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-gray-100 font-sans pb-12 relative">
      <div className="bg-black/50 backdrop-blur-xl border-b border-white/10 sticky top-0 z-40">
        <div className="max-w-6xl mx-auto px-6 py-4 flex items-center justify-between">
          <button onClick={onBack} className="flex items-center gap-2 px-4 py-2 rounded-full hover:bg-white/10 transition-colors text-gray-400 hover:text-white font-semibold text-sm border border-white/10">
            <ArrowLeft className="w-5 h-5" /> Back
          </button>
          <div className="flex items-center gap-3">
            <button onClick={handleShare} className="p-2 text-gray-400 hover:text-white hover:bg-white/10 rounded-full transition-all">
              <Share2 className="w-5 h-5" />
            </button>
            {isOwner && (
              <button onClick={() => fileInputRef.current?.click()} className="px-4 py-2 bg-indigo-500/10 text-indigo-400 rounded-full font-bold text-sm border border-indigo-500/20">
                Update Cover
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-6 mt-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-6">
            <div className="w-full h-[400px] bg-white/5 border border-white/10 rounded-[2rem] overflow-hidden flex items-center justify-center">
              {currentImage ? <img src={currentImage} alt="" className="w-full h-full object-cover" /> : <ImageIcon className="w-16 h-16 text-gray-700" />}
            </div>
            <div className="bg-white/5 border border-white/10 rounded-[2rem] p-8">
              <h2 className="text-xl font-bold mb-4 flex items-center gap-2"><LayoutGrid className="w-5 h-5 text-indigo-400" /> Description</h2>
              <p className="text-gray-300 leading-relaxed whitespace-pre-wrap">{project.description}</p>
            </div>

            <div className="bg-white/5 border border-white/10 rounded-[2rem] p-8">
               <h3 className="text-xl font-bold mb-6 flex items-center gap-2"><MessageCircle className="w-5 h-5 text-indigo-400" /> Discussion ({comments.length})</h3>
               <div className="flex gap-3 mb-8">
                 <input type="text" value={newComment} onChange={(e) => setNewComment(e.target.value)} placeholder="Add a comment..." className="flex-1 bg-black/30 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-indigo-500" />
                 <button onClick={handleAddComment} className="bg-indigo-600 p-3 rounded-xl"><Send className="w-5 h-5" /></button>
               </div>
               <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                 {comments.map((c, i) => (
                   <div key={i} className="bg-white/5 p-4 rounded-xl border border-white/5">
                      <p className="font-bold text-indigo-300 text-sm">{c.userName}</p>
                      <p className="text-gray-300 text-sm">{c.text}</p>
                   </div>
                 ))}
               </div>
            </div>
          </div>

          <div className="space-y-6">
            <div className="bg-white/5 border border-white/10 rounded-[2rem] p-8 backdrop-blur-md relative shadow-xl">
              <div className="flex justify-between items-start mb-4">
                 <span className="bg-indigo-500/20 text-indigo-300 border border-indigo-500/30 px-3 py-1 rounded-full text-[10px] font-bold uppercase">{project.category || 'Project'}</span>
                 <button onClick={handleLike} className={`flex items-center gap-2 px-3 py-1 rounded-full border transition-all ${isLikedByMe ? 'bg-pink-500/20 text-pink-500 border-pink-500/50' : 'text-gray-400 border-white/10'}`}>
                   <Heart className={`w-4 h-4 ${isLikedByMe ? 'fill-current' : ''}`} /> <span>{likes.length}</span>
                 </button>
              </div>
              <h1 className="text-3xl font-extrabold text-white mb-6 leading-tight">{project.title}</h1>
              <button onClick={() => setIsAppRunning(true)} className="w-full bg-white text-black py-4 rounded-xl font-bold flex justify-center items-center gap-2 mb-8 hover:bg-gray-200 transition-colors">
                Launch Simulator <ExternalLink className="w-5 h-5" />
              </button>
              <div className="space-y-3">
                <div className="flex items-center gap-4 bg-black/40 border border-white/5 p-4 rounded-xl">
                  <User className="w-5 h-5 text-indigo-400" />
                  <div><p className="text-[10px] text-gray-500 uppercase font-bold">Author</p><p className="text-sm font-semibold text-white">{liveAuthorName || project.authorName || 'Student'}</p></div>
                </div>
                <div className="flex items-center gap-4 bg-black/40 border border-white/5 p-4 rounded-xl">
                  <Calendar className="w-5 h-5 text-purple-400" />
                  <div><p className="text-[10px] text-gray-500 uppercase font-bold">Stats</p><p className="text-sm font-semibold text-white">{project.views || 0} Views</p></div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {isAppRunning && project.liveDemoUrl && (
        <div className="fixed inset-0 z-[200] bg-black/90 flex flex-col">
          <div className="flex items-center justify-between p-4 bg-black border-b border-white/10 shadow-2xl">
            <span className="text-white font-bold text-sm tracking-wider">LIVE PREVIEW</span>
            <button onClick={() => setIsAppRunning(false)} className="px-4 py-2 bg-red-500 text-white rounded-lg font-bold text-xs">Close</button>
          </div>
          <iframe src={project.liveDemoUrl} title="preview" className="flex-1 w-full bg-white" sandbox="allow-scripts allow-same-origin allow-forms allow-popups" />
        </div>
      )}
      <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={(e) => {/* Handle existing image logic */}} />
    </div>
  );
}

export default ProjectDetails;
